import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [user, setUser] = useState(null);
  const [view, setView] = useState("dashboard");
  const [students, setStudents] = useState([]);
  const [id, setId] = useState("");
  const [pass, setPass] = useState("");

  useEffect(() => {
    if (user?.role === 'admin') loadStudents();
  }, [user]);

  const loadStudents = () => axios.get('http://localhost:3000/api/admin/students').then(res => setStudents(res.data));

  const updateData = (sid, data) => {
    axios.put(`http://localhost:3000/api/admin/update/${encodeURIComponent(sid)}`, data).then(loadStudents);
  };

  if (!user) {
    return (
      <div style={st.loginBg}>
        <div style={st.loginCard}>
          <h2 style={{color: '#1a73e8'}}>UOB PORTAL 2026</h2>
          <input placeholder="ID (admin ama BCS/...)" onChange={e => setId(e.target.value)} style={st.in} />
          <input type="password" placeholder="Password" onChange={e => setPass(e.target.value)} style={st.in} />
          <button onClick={() => {
            axios.post('http://localhost:3000/api/login', { id, password: pass })
            .then(res => setUser(res.data)).catch(e => alert(e.response.data.message));
          }} style={st.loginBtn}>LOGIN</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'Segoe UI' }}>
      {/* SIDEBAR - Sida sawirkaaga (cite: 1000004081.jpg) */}
      <div style={st.sidebar}>
        <div style={{padding: '20px', textAlign: 'center', borderBottom: '1px solid #444'}}>
           <img src="https://via.placeholder.com/50" alt="Logo" style={{borderRadius: '50%'}} />
           <p>UOB Portal</p>
        </div>
        <button onClick={() => setView("dashboard")} style={view === "dashboard" ? st.activeM : st.menuB}>🏠 Dashboard</button>
        {user.role === 'admin' ? (
          <>
            <button onClick={() => setView("exam")} style={view === "exam" ? st.activeM : st.menuB}>📝 Geli Imtixaanka</button>
            <button onClick={() => setView("attendance")} style={view === "attendance" ? st.activeM : st.menuB}>📅 Xadiriska</button>
            <button onClick={() => setView("fees")} style={view === "fees" ? st.activeM : st.menuB}>💰 Lacagaha</button>
          </>
        ) : (
          <button onClick={() => setView("myresults")} style={st.menuB}>📊 My Results</button>
        )}
        <button onClick={() => setUser(null)} style={st.logoutB}>Logout</button>
      </div>

      {/* MAIN CONTENT */}
      <div style={{ flex: 1, padding: '30px', background: '#f4f7f6', overflowY: 'auto' }}>
        {user.role === 'admin' ? (
          <div>
            <h2>Maamulka: {view.toUpperCase()}</h2>
            <table style={st.table}>
              <thead style={{background: '#1a73e8', color: 'white'}}>
                <tr><th>ID</th><th>Magaca</th><th>Action / Data</th><th>Attendance</th></tr>
              </thead>
              <tbody>
                {students.slice(0, 50).map(s => (
                  <tr key={s.id} style={{textAlign: 'center', borderBottom: '1px solid #ddd'}}>
                    <td style={{padding: '12px'}}>{s.id}</td><td>{s.magaca}</td>
                    <td>
                      {view === "exam" ? (
                        <div style={{display: 'flex', gap: '5px'}}>
                          <input type="number" placeholder="B1" style={st.miniIn} onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, bil1: e.target.value}})} defaultValue={s.imtixaan.bil1} />
                          <input type="number" placeholder="Mid" style={st.miniIn} onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, midterm: e.target.value}})} defaultValue={s.imtixaan.midterm} />
                          <input type="number" placeholder="B3" style={st.miniIn} onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, bil3: e.target.value}})} defaultValue={s.imtixaan.bil3} />
                          <input type="number" placeholder="Fin" style={st.miniIn} onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, final: e.target.value}})} defaultValue={s.imtixaan.final} />
                        </div>
                      ) : view === "attendance" ? (
                        <button onClick={() => updateData(s.id, {joogay: s.joogay + 1})} style={st.tick}>√</button>
                      ) : (
                        <select onChange={e => updateData(s.id, {lacagta: e.target.value})} defaultValue={s.lacagta}>
                          <option value="Ma bixin">Ma bixin</option><option value="Bixiyey">Bixiyey</option>
                        </select>
                      )}
                    </td>
                    <td>{Math.round((s.joogay / (s.joogay + s.maqnaa || 1)) * 100)}%</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div style={{textAlign: 'center'}}>
            <div style={st.studentCard}>
              <h1>Natiijada Ardayga: {user.id}</h1>
              <div style={st.grid}>
                <div style={st.infoBox}><h4>Bilaha 1</h4><h3>{user.imtixaan.bil1}%</h3></div>
                <div style={st.infoBox}><h4>Mid-Term</h4><h3>{user.imtixaan.midterm}%</h3></div>
                <div style={st.infoBox}><h4>Bilaha 3</h4><h3>{user.imtixaan.bil3}%</h3></div>
                <div style={st.infoBox}><h4>Final Exam</h4><h3>{user.imtixaan.final}%</h3></div>
              </div>
              <div style={{marginTop: '20px'}}>
                <p>Xadiriska: <b>{Math.round((user.joogay / (user.joogay + user.maqnaa || 1)) * 100)}%</b></p>
                <p>Lacagta: <b style={{color: user.lacagta === 'Bixiyey' ? 'green' : 'red'}}>{user.lacagta}</b></p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

